class OrchestrationFailureType(str, Enum):
    WRONG_INTENT        = "wrong_intent"        # intent classified incorrectly
    STALE_CONTEXT       = "stale_context"       # prior turn's entities bleed into new turn
    PROMPT_INJECTION    = "prompt_injection"    # user content overrides system prompt
    RAG_FAILURE         = "rag_failure"         # retrieval returns wrong or empty chunks
    TOOL_RESULT_UNVALIDATED = "tool_result_unvalidated"  # tool output used without schema check

@dataclass
class OrchestrationFailureRecord:
    failure_type:   OrchestrationFailureType
    phase:          str          # journey phase where failure occurred
    root_cause:     str          # specific code path or config error
    reproducible:   bool         # can be reproduced with the same input
    severity_score: int          # 1-10

    def needs_immediate_fix(self) -> bool:
        return (
            self.failure_type == OrchestrationFailureType.PROMPT_INJECTION
            or self.severity_score >= 8
        )

def fmea_to_ac(entry: FMEAEntry) -> str:
    """Convert an FMEA entry to Gherkin acceptance criterion."""
    return (
        f"GIVEN {entry.detection_method} is active\n"
        f"WHEN the failure mode '{entry.failure_mode}' occurs\n"
        f"THEN {entry.recommended_action}\n"
        f"# RPN: {entry.rpn} [{entry.risk_level()}]"
    )

# Generate ACs for all critical and high failures
for entry in ranked:
    if entry.risk_level() in ("critical", "high"):
        print(fmea_to_ac(entry))
        print()

from dataclasses import dataclass, field

@dataclass
class FMEAWorkshopOutput:
    journey_id:    str
    session_date:  str           # ISO date string
    participants:  list[str]
    entries:       list[FMEAEntry]
    open_items:    list[str]     # unresolved scoring disagreements
    sprint_tickets: list[str]   # ticket IDs created from critical/high entries

    def critical_count(self) -> int:
        return sum(1 for e in self.entries if e.risk_level() == "critical")

    def high_count(self) -> int:
        return sum(1 for e in self.entries if e.risk_level() == "high")

    def unmitigated_critical(self) -> list[FMEAEntry]:
        """Critical entries without a detection method assigned."""
        return [e for e in self.entries
                if e.risk_level() == "critical"
                and not e.detection_method]

    def is_sprint_ready(self) -> bool:
        """True if all critical failures have a detection method and a ticket."""
        return (
            len(self.unmitigated_critical()) == 0
            and len(self.open_items) == 0
        )
